// Load state — $getWorkflowStaticData is the correct API for n8n 2.4.x task runner
// Dedup by post_id — stable, unique, no crypto needed
const staticData = $getWorkflowStaticData('global');

// Bootstrap guard: re-seed if state was ever cleared
if (!staticData.seen_ids || staticData.seen_ids.length === 0) {
  staticData.seen_ids = ["mikoslab/399", "mikoslab/400", "mikoslab/401", "mikoslab/403", "mikoslab/404", "mikoslab/405", "mikoslab/406", "mikoslab/407", "mikoslab/408", "mikoslab/409", "mikoslab/410", "mikoslab/411", "mikoslab/412", "mikoslab/413", "mikoslab/414", "mikoslab/415", "mikoslab/416", "mikoslab/417", "mikoslab/418", "mikoslab/419"];
}

// Parse HTML
const html = $input.first().json.data;
const postSections = html.split(/(?=<div[^>]+class="[^"]*tgme_widget_message_wrap[^"]*")/);

const posts = [];
for (const section of postSections) {
  const postIdMatch = section.match(/data-post="(mikoslab\/(\d+))"/);
  if (!postIdMatch) continue;

  const postId = postIdMatch[1];
  const postNum = postIdMatch[2];

  const dateMatch = section.match(/datetime="([^"]+)"/);
  const dateStr = dateMatch ? dateMatch[1].substring(0, 10) : 'unknown';

  const textMatch = section.match(/<div[^>]+class="[^"]*tgme_widget_message_text[^"]*"[^>]*>([\s\S]*?)<\/div>/);
  let rawText = '';
  if (textMatch) {
    rawText = textMatch[1]
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<a[^>]+href="[^"]+"[^>]*>([^<]*)<\/a>/gi, '$1')
      .replace(/<[^>]+>/g, '')
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
      .trim();
  }

  posts.push({ post_id: postId, post_num: parseInt(postNum), date: dateStr, text: rawText, url: `https://t.me/${postId}` });
}

const postMap = new Map();
for (const p of posts) postMap.set(p.post_id, p);
const uniquePosts = [...postMap.values()].sort((a, b) => a.post_num - b.post_num);

const seenIds = staticData.seen_ids;
const newPosts = uniquePosts.filter(p => !seenIds.includes(p.post_id));

console.log(`Parsed ${uniquePosts.length} unique posts, ${newPosts.length} new`);

return [{ json: { posts: uniquePosts, newPosts, totalParsed: uniquePosts.length, newCount: newPosts.length } }];

// Update state and build notification
const staticData = $getWorkflowStaticData('global');
const { newPosts, newCount } = $input.first().json;

// Append new post IDs to seen_ids, cap at 500 FIFO
const seenIds = staticData.seen_ids || [];
for (const p of newPosts) seenIds.push(p.post_id);
staticData.seen_ids = seenIds.length > 500 ? seenIds.slice(seenIds.length - 500) : seenIds;

// Build Telegram message
const postsToShow = newCount >= 5 ? newPosts.slice(0, 3) : newPosts;
const remainder = newCount >= 5 ? newCount - 3 : 0;

let message = `📡 *Miko's Lab — ${newCount} new post${newCount > 1 ? 's' : ''}*\n`;

for (const p of postsToShow) {
  const truncated = p.text.length > 200 ? p.text.substring(0, 200) + '...' : p.text;
  const postNum = p.post_id.replace('mikoslab/', '');
  message += `\n[Post ${postNum}] ${p.date}\n${truncated}\n🔗 ${p.url}\n`;
}

if (remainder > 0) message += `\n_(+${remainder} more)_`;

return [{ json: { message, newCount } }];

// No new posts — force-write state so n8n persists staticData to SQLite
const staticData = $getWorkflowStaticData('global');
// Touch seen_ids with slice() to create a new array reference — marks dirty for n8n persistence
const ids = staticData.seen_ids || [];
staticData.seen_ids = ids.slice();
console.log('mikos-lab-tracker: no new posts. seen_ids count:', ids.length);
return [{ json: { status: 'no_new_posts', seen_count: ids.length } }];

